namespace sv_d77d08709bdd44cfbb2712ce31a681ba.Services;

public record Product(int Id, string Name, decimal Price, string Category, double Rating, bool InStock, string ImageUrl);
public record ProductFilter(List<string>? Categories, decimal? MinPrice, decimal? MaxPrice, bool InStockOnly);
public record PagedResult<T>(List<T> Items, int TotalCount, int Page, int PageSize);

public interface IProductService
{
    Task<PagedResult<Product>> SearchAsync(ProductFilter filter, string sortBy, int page, int pageSize);
    Task<List<string>> GetCategoriesAsync();
}

@using sv_d77d08709bdd44cfbb2712ce31a681ba.Services

<div class="card h-100 product-card" @onclick="HandleCardClick" style="cursor: pointer;" role="article">
    <div class="card-img-top bg-secondary bg-opacity-25 d-flex align-items-center justify-content-center"
         style="height: 200px;"
         role="img"
         aria-label="@Product.Name">
        <span class="text-muted fs-6 text-center px-2">@Product.Name</span>
    </div>
    <div class="card-body d-flex flex-column">
        <h5 class="card-title">@Product.Name</h5>
        <p class="card-text fw-bold text-success mb-1">@Product.Price.ToString("C")</p>
        <p class="card-text mb-2" title="@($"{Product.Rating:F1} out of 5")">@GetStarRating(Product.Rating)</p>
        @if (!Product.InStock)
        {
            <span class="badge bg-danger mb-2 align-self-start">Out of Stock</span>
        }
        <button class="btn btn-primary mt-auto"
                disabled="@(!Product.InStock)"
                @onclick="HandleAddToCart"
                @onclick:stopPropagation="true">
            Add to Cart
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Product Product { get; set; } = default!;

    [Parameter]
    public EventCallback<Product> OnSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    private async Task HandleCardClick() => await OnSelected.InvokeAsync(Product);

    private async Task HandleAddToCart() => await OnAddToCart.InvokeAsync(Product);

    private static string GetStarRating(double rating)
    {
        int filled = (int)Math.Round(rating);
        return new string('★', filled) + new string('☆', 5 - filled);
    }
}

@using sv_d77d08709bdd44cfbb2712ce31a681ba.Services

<div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-4">
