    {
        <div class="col">
            <ProductCard Product="product"
                         OnSelected="OnProductSelected"
                         OnAddToCart="OnAddToCart" />
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public List<Product> Products { get; set; } = [];

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }
}

@using sv_d77d08709bdd44cfbb2712ce31a681ba.Services

<div class="p-3 border rounded bg-light">
    <h5 class="mb-3">Filters</h5>

    <div class="mb-3">
        <h6>Category</h6>
        @foreach (var category in Categories)
        {
            <div class="form-check">
                <input class="form-check-input"
                       type="checkbox"
                       id="@($"cat-{category}")"
                       checked="@selectedCategories.Contains(category)"
                       @onchange="e => ToggleCategory(category, (bool)e.Value!)" />
                <label class="form-check-label" for="@($"cat-{category}")">@category</label>
            </div>
        }
    </div>

    <div class="mb-3">
        <h6>Price Range</h6>
        <div class="d-flex gap-2">
            <input type="number"
                   class="form-control"
                   placeholder="Min"
                   @bind="minPrice"
                   @bind:event="onchange" />
            <input type="number"
                   class="form-control"
                   placeholder="Max"
                   @bind="maxPrice"
                   @bind:event="onchange" />
        </div>
    </div>

    <div class="mb-3">
        <div class="form-check">
            <input class="form-check-input"
                   type="checkbox"
                   id="instock-only"
                   @bind="inStockOnly" />
            <label class="form-check-label" for="instock-only">In Stock Only</label>
        </div>
    </div>

    <div class="d-grid gap-2">
        <button class="btn btn-primary" @onclick="ApplyFilters">Apply Filters</button>
        <button class="btn btn-outline-secondary" @onclick="ClearFilters">Clear Filters</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public List<string> Categories { get; set; } = [];

    [Parameter]
    public EventCallback<ProductFilter> OnFilterApplied { get; set; }

    [Parameter]
    public EventCallback OnFilterCleared { get; set; }

    private HashSet<string> selectedCategories = [];
    private decimal? minPrice;
    private decimal? maxPrice;
    private bool inStockOnly;

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            selectedCategories.Add(category);
        else
            selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        var filter = new ProductFilter(
            Categories: selectedCategories.Count > 0 ? selectedCategories.ToList() : null,
            MinPrice: minPrice,
            MaxPrice: maxPrice,
            InStockOnly: inStockOnly);
        await OnFilterApplied.InvokeAsync(filter);
    }

    private async Task ClearFilters()
    {
        selectedCategories.Clear();
        minPrice = null;
        maxPrice = null;
        inStockOnly = false;
        await OnFilterCleared.InvokeAsync();
    }
}

@page "/catalog"
@using sv_d77d08709bdd44cfbb2712ce31a681ba.Components.Catalog
@using sv_d77d08709bdd44cfbb2712ce31a681ba.Services
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h1 class="mb-4">Product Catalog</h1>

@if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-sm btn-outline-danger ms-3" @onclick="RetryLoad">Retry</button>
    </div>
}
else
{
    <div class="row">
        <div class="col-md-3">
            <CatalogFilters Categories="categories"
                            OnFilterApplied="HandleFilterApplied"
                            OnFilterCleared="HandleFilterCleared" />
        </div>

        <div class="col-md-9">
            <CatalogToolbar SortBy="@sortBy"
                            TotalCount="@totalCount"
                            Page="@currentPage"
                            PageSize="@pageSize"
                            OnSortChanged="HandleSortChanged" />

            @if (isLoading)
            {
                <div class="d-flex justify-content-center py-5">
                    <div class="spinner-border text-primary" role="status">
                        <span class="visually-hidden">Loading products...</span>
                    </div>
                </div>
            }
            else if (products.Count == 0)
            {
                <div class="text-center py-5 text-muted">
                    <p class="fs-4">No products found</p>
                    <p>Try adjusting your filters or clearing them.</p>
                </div>
            }
            else
            {
                <ProductGrid Products="products"
                             OnProductSelected="HandleProductSelected"
                             OnAddToCart="HandleAddToCart" />

                @if (totalPages > 1)
                {
                    <div class="mt-4">
                        <CatalogPagination CurrentPage="currentPage"
                                           TotalPages="totalPages"
                                           OnPageChanged="HandlePageChanged" />
                    </div>
                }
            }
        </div>
    </div>
}

@code {
    /// <summary>
    /// Raised when a product card is clicked so the parent can navigate to a detail page.
    /// </summary>
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private List<Product> products = [];
    private List<string> categories = [];
    private ProductFilter currentFilter = new(null, null, null, false);
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private const int pageSize = 12;
    private int totalCount;
    private int totalPages;
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        try
        {
            isLoading = true;
            errorMessage = null;

            var categoriesTask = categories.Count == 0
                ? ProductService.GetCategoriesAsync()
                : Task.FromResult(categories);
            var searchTask = ProductService.SearchAsync(currentFilter, sortBy, currentPage, pageSize);

            await Task.WhenAll(categoriesTask, searchTask);

            categories = await categoriesTask;
            var result = await searchTask;

            products = result.Items;
            totalCount = result.TotalCount;
            totalPages = totalCount > 0
                ? (int)Math.Ceiling((double)totalCount / pageSize)
                : 1;
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
            products = [];
            totalCount = 0;
            totalPages = 1;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task HandleFilterApplied(ProductFilter filter)
    {
        currentFilter = filter;
        currentPage = 1;
        await LoadDataAsync();
    }

    private async Task HandleFilterCleared()
    {
        currentFilter = new ProductFilter(null, null, null, false);
        currentPage = 1;
        await LoadDataAsync();
    }

    private async Task HandleSortChanged(string newSort)
    {
        sortBy = newSort;
        currentPage = 1;
        await LoadDataAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        currentPage = page;
        await LoadDataAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder for cart integration
        return Task.CompletedTask;
    }

    private async Task RetryLoad()
    {
        await LoadDataAsync();
    }
}

